<script setup lang="ts">const{toasts,remove}=useToast();const styles={success:{icon:'mdi:check-circle',wrap:'border-emerald-200 bg-emerald-50 text-emerald-900',accent:'text-emerald-600'},error:{icon:'mdi:close-circle',wrap:'border-red-200 bg-red-50 text-red-900',accent:'text-red-600'},warning:{icon:'mdi:alert-circle',wrap:'border-amber-200 bg-amber-50 text-amber-900',accent:'text-amber-600'},info:{icon:'mdi:information',wrap:'border-blue-200 bg-blue-50 text-blue-900',accent:'text-blue-600'}}</script>
<template><Teleport to="body"><div class="fixed right-4 top-4 z-[160] grid w-[min(92vw,380px)] gap-3"><TransitionGroup name="toast"><article v-for="toast in toasts" :key="toast.id" class="flex gap-3 rounded-2xl border p-4 shadow-xl" :class="styles[toast.type].wrap"><Icon :name="styles[toast.type].icon" size="25" :class="styles[toast.type].accent"/><div class="min-w-0 flex-1"><b class="block">{{toast.title}}</b><p class="mt-1 text-sm leading-5 opacity-80">{{toast.message}}</p></div><button class="self-start" aria-label="Tutup alert" @click="remove(toast.id)"><Icon name="mdi:close"/></button></article></TransitionGroup></div></Teleport></template>
<style scoped>.toast-enter-active,.toast-leave-active{transition:all .3s ease}.toast-enter-from,.toast-leave-to{opacity:0;transform:translateX(30px)}</style>
